var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐야, 작전 시작 전에 갑자기 불러 세워서 무슨 중요한 일인가 했더니…….","JPN":"何だよ、作戦開始前に急に呼び出して、どんな重要なことかと思ったら……","ENG":"Huh? I thought it was something important because you asked to see me right before the operation...","TWN":"搞什麼？作戰開​​始前突然叫住我，還以為你有什麼重要的事情……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이런 곳에서 이벤트를 준비하고 있었던 거야?","JPN":"こんなところでイベントの準備をしていたのか？","ENG":"But you were just planning an event in here?","TWN":"你要在這種地方舉辦活動？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"근데 미안해서 어쩌나?","JPN":"でも、まいったな。","ENG":"I'm sorry to tell you this, but...","TWN":"但真是抱歉欸？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나 케이크는 별로 안 좋아하거든. 근손실 온단 말이야.","JPN":"アタシ、ケーキはあまり好きじゃないんだよな。筋肉が減るからさ。","ENG":"I don't like cake. It makes me lose muscle mass.","TWN":"我不太喜歡蛋糕，蛋糕會害肌肉會流失。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"푸핫! 농담이니까 실망한 표정 짓지 말라고. 예의상 한 입은 먹어주지.","JPN":"ぷはっ！　冗談だからがっかりすんなって。礼儀として、一口は食べてやるよ。","ENG":"Haha! I'm just kidding! You don't have to look so disappointed. I'll eat a bite just for you.","TWN":"噗哧！別露出一副失望的表情，我開玩笑呢。出於禮貌我會咬一口的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"설마 삐진 건 아니지? 하이브 컨트롤 뒤에서 암약하던 최고 관리자가 이런 성격인 줄은 몰랐는데?","JPN":"まさか拗ねたんじゃないよな？　ハイブコントロールの裏で暗躍していた最高管理者がこんな性格だとは知らなかったんだけど？","ENG":"You're not upset, are you? I didn't expect the Supreme Administrator, who worked secretly behind Hive Control, to have such a sensitive personality.","TWN":"你該不會在不高興吧？沒想到暗中操縱巢穴控制系統的最高管理者竟然是這副德性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 옛날 성격 같았으면 그 잘난 낯짝에 한 방 날려줬겠지만…….","JPN":"まあ、昔だったら、あのろくでなしの面に一発お見舞いしてやってたんだろうけど……","ENG":"Well, the old me would've socked up right in that mug of yours, but...","TWN":"唔，要是照我以前的脾氣，我一定會給你那張得意的臉來上一拳……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장이 된 지금은…… 나도 어느 정도는 당신 입장을 이해할 수 있을 것 같거든.","JPN":"戦隊長になった今は……アタシもある程度はあなたの立場が理解できると思う。","ENG":"I'm a Commander now... so I think I can understand where you're coming from.","TWN":"但如今，當我成為一位戰隊長……我好像多少可以理解你的立場。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……무섭지 않냐고?","JPN":"……怖くないかって？","ENG":"...Aren't I scared?","TWN":"……我不害怕嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 무섭지 않다면 거짓말이겠지. 아직도 그 화재가 아른아른 떠오를 지경이니까.","JPN":"怖くないわけないだろ。まだあの火事のことが脳裏をちらつくんだから。","ENG":"I'd be lying if I said I wasn't scared. I still remember glimpses of that fire.","TWN":"唔，說不害怕是假的。到現在，那場火災還隱隱約約浮現在我眼前。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 그런 나에게 손을 내밀어 준 게 우리 전대원 녀석들이거든.","JPN":"でも、そんなアタシに手を差し伸べてくれたのが、うちの戦隊員のやつらなんだ。","ENG":"But it was my division members who reached out to me.","TWN":"但向我伸出援手的是我的戰隊員。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그동안 힘든 일도, 즐거운 일도, 슬픈 일도……. 전부 그 녀석들과 함께 해왔어.","JPN":"辛いことも、楽しいことも、悲しいことも……全部あいつらと一緒だった。","ENG":"All the hardships, joys, and sorrow... I experienced it all while being next to them.","TWN":"那段時間，有過困難，有過快樂，有過悲傷……是他們陪我度過那些時光的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까 이건 세계를 위한 일도, 당신이 시킨 일도 아니야.","JPN":"だからこれは世界のためでも、あなたに命じられたからでもない。","ENG":"So this isn't something I'm doing for the world, or because you ordered me to.","TWN":"所以，我做這件事不是因為世界，也不是因為你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 당신이 누구고, 관리국이 어쩌고 인과율이 저쩌고 하는 이야기. 전혀 관심 없으니까.","JPN":"アタシはあなたが誰だろうと、管理局や因果律がなんだろうと、そんなのには全然興味がねえ。","ENG":"Because I'm not interested in who you are, or what this causality the Administration keeps talking is all about.","TWN":"我不管你是誰，管理局也好，因果律也罷。這些我根本不感興趣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 작전은 나 자신. 그리고…… 나의 소중한 전대원들을 구하기 위한 일이야.","JPN":"この作戦はアタシ自身、それと……大切な戦隊員たちを救うためにすることだからさ。","ENG":"This operation is for me. And... to save my precious division members.","TWN":"這個作戰是因為要拯救我自己，和我珍貴的戰隊員。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그런 섭섭한 표정 짓지 말라고.","JPN":"ふっ、そんな寂しそうな顔すんなって。","ENG":"Hah hah, don't be so sad.","TWN":"哈哈，別露出一副難過的表情嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 동료들을 구할 수단을 제시해 준 당신에게는 진심으로 감사하고 있으니까 말이지.","JPN":"同僚たちを救う手段を示してくれたあなたには、心から感謝しているんだから。","ENG":"I'm truly grateful to you for suggesting a way for me to save my comrades.","TWN":"我真的很感謝你，能提出拯救我的同伴的方法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 우주로 올라가기 전에……. 마지막으로 이 계약서에 서명하면 되는 거지?","JPN":"じゃあ、宇宙に行く前に……最後にこの契約書にサインすればいいんだな？","ENG":"Now, before I head up to outer space... I just have to sign this contract, right?","TWN":"來吧，在進入太空前……我只需要簽署這份合約就可以吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 잘 부탁한다고. 최고 관리자.","JPN":"じゃ、よろしくな。最高管理者。","ENG":"I look forward to working with you, Supreme Administrator.","TWN":"那就請多關照囉，最高管理者。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};